import{_ as i,o as a,c as s,ai as n}from"./chunks/framework.EKiYdDTS.js";const g=JSON.parse('{"title":"Recipes","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/recipes.md","filePath":"concepts/recipes.md","rawMarkdown":"# Recipes\\n\\nA recipe is a complete agent configuration — provider, model, skills, middleware, and config — packaged as a directory you can install and run. It\'s how you share and reuse agent setups.\\n\\n## What\'s in a recipe\\n\\n```\\nrecipes/coding-agent/\\n  ra.config.yaml     # full agent config\\n  skills/            # skills specific to this recipe\\n  middleware/         # middleware specific to this recipe\\n  README.md\\n```\\n\\nThe config file is a standard ra config. The skills and middleware directories follow the same conventions as any other ra project.\\n\\n## Using a recipe\\n\\nRun a recipe by name:\\n\\n```bash\\nra --recipe coding-agent \\"Fix the failing test in auth.ts\\"\\n```\\n\\nOr install one from a remote source:\\n\\n```bash\\nra recipe install github:user/my-agent-recipe\\nra recipe install npm:my-agent-recipe@latest\\n```\\n\\n## How config layering works\\n\\nWhen you use a recipe, its config merges with your other config sources:\\n\\n```\\ndefaults < recipe < config file < CLI flags\\n```\\n\\nThe recipe provides a baseline. Your local config file overrides it. CLI flags override everything. Array fields like `skillDirs` and `middleware` are prepended from the recipe, not replaced — so the recipe\'s skills add to yours rather than wiping them out.\\n\\n## Built-in recipes\\n\\nra ships with several recipes to get you started:\\n\\n| Recipe | What it does |\\n|--------|-------------|\\n| `coding-agent` | Full coding workflow with thinking, compaction, and specialist skills |\\n| `code-review-agent` | Focused code review with style guide awareness |\\n| `multi-agent` | Orchestrates multiple sub-agents for complex tasks |\\n\\n## Building your own\\n\\nA recipe is just a directory with a `ra.config.yaml`. Start from one of the built-in recipes, customize the system prompt, add skills for your domain, wire in middleware for your workflow.\\n\\nSee [Creating Recipes](/recipes/creating-recipes) for a step-by-step guide.\\n"}'),t={name:"concepts/recipes.md"};function r(o,e,l,c,p,d){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="recipes" tabindex="-1">Recipes <a class="header-anchor" href="#recipes" aria-label="Permalink to &quot;Recipes&quot;">​</a></h1><p>A recipe is a complete agent configuration — provider, model, skills, middleware, and config — packaged as a directory you can install and run. It&#39;s how you share and reuse agent setups.</p><h2 id="what-s-in-a-recipe" tabindex="-1">What&#39;s in a recipe <a class="header-anchor" href="#what-s-in-a-recipe" aria-label="Permalink to &quot;What&#39;s in a recipe&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>recipes/coding-agent/</span></span>
<span class="line"><span>  ra.config.yaml     # full agent config</span></span>
<span class="line"><span>  skills/            # skills specific to this recipe</span></span>
<span class="line"><span>  middleware/         # middleware specific to this recipe</span></span>
<span class="line"><span>  README.md</span></span></code></pre></div><p>The config file is a standard ra config. The skills and middleware directories follow the same conventions as any other ra project.</p><h2 id="using-a-recipe" tabindex="-1">Using a recipe <a class="header-anchor" href="#using-a-recipe" aria-label="Permalink to &quot;Using a recipe&quot;">​</a></h2><p>Run a recipe by name:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recipe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> coding-agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Fix the failing test in auth.ts&quot;</span></span></code></pre></div><p>Or install one from a remote source:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> recipe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github:user/my-agent-recipe</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> recipe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm:my-agent-recipe@latest</span></span></code></pre></div><h2 id="how-config-layering-works" tabindex="-1">How config layering works <a class="header-anchor" href="#how-config-layering-works" aria-label="Permalink to &quot;How config layering works&quot;">​</a></h2><p>When you use a recipe, its config merges with your other config sources:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>defaults &lt; recipe &lt; config file &lt; CLI flags</span></span></code></pre></div><p>The recipe provides a baseline. Your local config file overrides it. CLI flags override everything. Array fields like <code>skillDirs</code> and <code>middleware</code> are prepended from the recipe, not replaced — so the recipe&#39;s skills add to yours rather than wiping them out.</p><h2 id="built-in-recipes" tabindex="-1">Built-in recipes <a class="header-anchor" href="#built-in-recipes" aria-label="Permalink to &quot;Built-in recipes&quot;">​</a></h2><p>ra ships with several recipes to get you started:</p><table tabindex="0"><thead><tr><th>Recipe</th><th>What it does</th></tr></thead><tbody><tr><td><code>coding-agent</code></td><td>Full coding workflow with thinking, compaction, and specialist skills</td></tr><tr><td><code>code-review-agent</code></td><td>Focused code review with style guide awareness</td></tr><tr><td><code>multi-agent</code></td><td>Orchestrates multiple sub-agents for complex tasks</td></tr></tbody></table><h2 id="building-your-own" tabindex="-1">Building your own <a class="header-anchor" href="#building-your-own" aria-label="Permalink to &quot;Building your own&quot;">​</a></h2><p>A recipe is just a directory with a <code>ra.config.yaml</code>. Start from one of the built-in recipes, customize the system prompt, add skills for your domain, wire in middleware for your workflow.</p><p>See <a href="/ra/recipes/creating-recipes.html">Creating Recipes</a> for a step-by-step guide.</p>`,20)])])}const u=i(t,[["render",r]]);export{g as __pageData,u as default};
